--
-- Table structure for table `simulate_transfers`
--

CREATE TABLE `simulate_transfers` (
  `id` varchar(36) NOT NULL,
  `transfer_id` varchar(36) NOT NULL,
  `quote_id` varchar(36) DEFAULT NULL,
